import SwiftUI

struct ExerciseLibraryView: View { @EnvironmentObject private var state:AppState; var body: some View { NavigationStack{ ScrollView{ LazyVGrid(columns:[GridItem(.flexible()),GridItem(.flexible())], spacing:14){ ForEach(MuscleGroup.allCases){ group in NavigationLink{ ExerciseListView(group:group) } label:{ VStack(alignment:.leading,spacing:16){ Image(systemName:group.icon).font(.title).foregroundStyle(ForgeTheme.accent); Text(group.rawValue).font(.headline).foregroundStyle(.primary); Text("\(state.availableExercises.filter{$0.muscleGroup == group}.count) exercises").font(.caption).foregroundStyle(.secondary) }.frame(maxWidth:.infinity,alignment:.leading).padding(16).background(ForgeTheme.card).clipShape(RoundedRectangle(cornerRadius:24,style:.continuous)) } } }.padding(20) }.background(ForgeTheme.background.ignoresSafeArea()).navigationTitle("Exercises") } } }
struct ExerciseListView: View { @EnvironmentObject private var state:AppState; let group:MuscleGroup; var body: some View { List{ ForEach(state.availableExercises.filter{$0.muscleGroup == group}){ exercise in NavigationLink{ ExerciseDetailView(exercise:exercise) } label:{ HStack(spacing:14){ RoundedRectangle(cornerRadius:14).fill(ForgeTheme.soft).frame(width:56,height:56).overlay(Image(systemName:group.icon).foregroundStyle(ForgeTheme.accent)); VStack(alignment:.leading,spacing:4){ Text(exercise.name).font(.headline); Text("\(exercise.level.rawValue) • \(exercise.equipment.map(\.rawValue).joined(separator:", "))").font(.caption).foregroundStyle(.secondary) } } } } }.navigationTitle(group.rawValue) } }
